args.sparql:
SELECT (MAX(?attendance) AS ?maxAttendance) WHERE {
  ?series wdt:P31 wd:Q82033;
          wdt:P527 wd:Q2628;
          wdt:P527 wd:Q10985;
          wdt:P585 ?eventDate.
  FILTER (YEAR(?eventDate) >= 1977 && YEAR(?eventDate) <= 2009)
  ?game wdt:P1545 ?series;
        wdt:P1442 ?attendance.
}

SELECT (MAX(?attendance) AS ?maxAttendance) WHERE {
  ?series wdt:P31 wd:Q1453300;  # National League Championship Series
  ?game wdt:P1545 ?series;
        wd:Q2628 wdt:P175 ?game;
        wd:Q10985 wdt:P175 ?game;
        wdt:P1442 ?attendance;
        wdt:P585 ?eventDate.
  FILTER (YEAR(?eventDate) >= 1977 && YEAR(?eventDate) <= 2009)
}
